// FormatBytes returns a human-readable byte size.
func FormatBytes(b int64) string {
	const unit = 1024
	if b < unit {
		return fmt.Sprintf("%d B", b)
	}
	div, exp := int64(unit), 0
	for n := b / unit; n >= unit; n /= unit {
		div *= unit
		exp++
	}
	return fmt.Sprintf("%.1f %cB", float64(b)/float64(div), "KMGTPE"[exp])
}

// FormatTime returns a formatted time string.
func FormatTime(t time.Time) string {
	if t.IsZero() {
		return "Never"
	}
	return t.Format("Jan 02, 2006 15:04")
}

// FormatTimeShort returns a short formatted time string.
func FormatTimeShort(t time.Time) string {
	if t.IsZero() {
		return "Never"
	}
	return t.Format("Jan 02, 15:04")
}

// FormatDate returns a date-only formatted string.
func FormatDate(t time.Time) string {
	if t.IsZero() {
		return "N/A"
	}
	return t.Format("Jan 02, 2006")
}

// TruncateHash shortens a hash for display.
func TruncateHash(h string) string {
	if len(h) <= 12 {
		return h
	}
	return h[:12] + "..."
}

// TruncateKey shortens a key for display.
func TruncateKey(k string) string {
	if len(k) <= 40 {
		return k
	}
	return "..." + k[len(k)-37:]
}

// ContentTypeIcon returns an icon name for a content type.
func ContentTypeIcon(ct string) string {
	if strings.HasPrefix(ct, "image/") {
		return "file"
	}
	if strings.HasPrefix(ct, "video/") {
		return "file"
	}
	if strings.HasPrefix(ct, "text/") {
		return "file-text"
	}
	return "file"
}

